  Future<String?> _openCamera(Map<String, dynamic> options) async {
    final cameras = await availableCameras();
    if (cameras.isEmpty) return null;

    final preferFront = options['facing'] == 'front';
    CameraDescription selectedCamera = cameras.first;
    for (final camera in cameras) {
      if (preferFront &&
          camera.lensDirection == CameraLensDirection.front) {
        selectedCamera = camera;
        break;
      } else if (!preferFront &&
          camera.lensDirection == CameraLensDirection.back) {
        selectedCamera = camera;
        break;
      }
    }

    if (!mounted) return null;

    final result = await Navigator.push<String>(
      context,
      MaterialPageRoute(
        builder: (context) => CameraScreen(camera: selectedCamera),
      ),
    );

    return result;
  }

  Future<void> _handleNotificationRequest(String message) async {
    try {
      final data = jsonDecode(message);
